import { useEffect, useState } from "react";

export function useDebounce(value, delay = 400) {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debounced;
}

export default function SearchBox() {
  const [query, setQuery] = useState("");
  const debouncedQuery = useDebounce(query);

  useEffect(() => {
    if (!debouncedQuery) return;
    console.log("Search for:", debouncedQuery);
  }, [debouncedQuery]);

  return <input value={query} onChange={(e) => setQuery(e.target.value)} />;
}

import { useState } from "react";

export default function TodoApp() {
  const [text, setText] = useState("");
  const [todos, setTodos] = useState([]);

  const addTodo = () => {
    if (!text.trim()) return;
    setTodos((prev) => [...prev, { id: Date.now(), text, done: false }]);
    setText("");
  };

  const toggleTodo = (id) => {
    setTodos((prev) =>
      prev.map((todo) => (todo.id === id ? { ...todo, done: !todo.done } : todo))
    );
  };

  const completedCount = todos.filter((todo) => todo.done).length;

  return (
    <section>
      <input value={text} onChange={(e) => setText(e.target.value)} />
      <button type="button" onClick={addTodo}>Add</button>
      <p>Completed: {completedCount}</p>
      <ul>
        {todos.map((todo) => (
          <li key={todo.id}>
            <button type="button" onClick={() => toggleTodo(todo.id)}>
              {todo.done ? "Undo" : "Done"}
            </button>
            <span style={{ textDecoration: todo.done ? "line-through" : "none" }}>
              {todo.text}
            </span>
          </li>
        ))}
      </ul>
    </section>
  );
}

import { useState } from "react";

export default function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Count: {count}</p>
      <button type="button" onClick={() => setCount((value) => value + 1)}>
        Increment
      </button>
      <button type="button" onClick={() => setCount((value) => value - 1)}>
        Decrement
      </button>
    </div>
  );
}

import { createContext, useContext, useState } from "react";

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);

  const login = (nextUser) => setUser(nextUser);
  const logout = () => setUser(null);

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const value = useContext(AuthContext);
  if (!value) throw new Error("useAuth must be used inside AuthProvider");
  return value;
}

import { useState } from "react";

export default function SignupForm() {
  const [form, setForm] = useState({ email: "", password: "" });
  const [errors, setErrors] = useState({});

  const validate = () => {
    const next = {};
    if (!form.email.includes("@")) next.email = "Enter a valid email";
    if (form.password.length < 8) next.password = "Password must be at least 8 characters";
    setErrors(next);
    return Object.keys(next).length === 0;
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    if (!validate()) return;
    console.log("Submitted", form);
  };

  return (
    <form onSubmit={handleSubmit}>
      <label>
        Email
        <input
          value={form.email}
          onChange={(e) => setForm({ ...form, email: e.target.value })}
        />
        {errors.email ? <p>{errors.email}</p> : null}
      </label>
      <label>
        Password
        <input
          type="password"
          value={form.password}
          onChange={(e) => setForm({ ...form, password: e.target.value })}
        />
        {errors.password ? <p>{errors.password}</p> : null}
      </label>
      <button type="submit">Sign up</button>
    </form>
  );
}

import { useMemo, useState } from "react";

const USERS = [
  { id: 1, name: "Asha", role: "admin" },
  { id: 2, name: "Ravi", role: "user" },
  { id: 3, name: "Maya", role: "user" },
];

export default function UserList() {
  const [query, setQuery] = useState("");

  const filteredUsers = useMemo(
    () => USERS.filter((user) => user.name.toLowerCase().includes(query.toLowerCase())),
    [query]
  );

  return (
    <section>
      <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Search users" />
      <ul>
        {filteredUsers.map((user) => (
          <li key={user.id}>{user.name} — {user.role}</li>
        ))}
      </ul>
    </section>
  );
}

